const getDocumentsFromLinks = async ({ links }: { links: string[] }) => {
  const splitter = new RecursiveCharacterTextSplitter();

  let docs: Document[] = [];

  await Promise.all(
    links.map(async (link) => {
      link =
        link.startsWith('http://') || link.startsWith('https://')
          ? link
          : `https://${link}`;

      try {
        const res = await axios.get(link, {
          responseType: 'arraybuffer',
        });

        // const isPdf = res.headers['content-type'] === 'application/pdf';

        // if (isPdf) {
        //   const pdfText = await pdfParse(res.data);
        //   const parsedText = pdfText.text
        //     .replace(/(\r\n|\n|\r)/gm, ' ')
        //     .replace(/\s+/g, ' ')
        //     .trim();

        //   const splittedText = await splitter.splitText(parsedText);
        //   const title = 'PDF Document';

        //   const linkDocs = splittedText.map((text) => {
        //     return new Document({
        //       pageContent: text,
        //       metadata: {
        //         title: title,
        //         url: link,
        //       },
        //     });
        //   });

        //   docs.push(...linkDocs);
        //   return;
        // }

        const parsedText = htmlToText(res.data.toString('utf8'), {
          selectors: [
            {
              selector: 'a',
              options: {
                ignoreHref: true,
              },
            },
          ],
        })
          .replace(/(\r\n|\n|\r)/gm, ' ')
          .replace(/\s+/g, ' ')
          .trim();

        const splittedText = await splitter.splitText(parsedText);
        const title = res.data
          .toString('utf8')
          .match(/<title>(.*?)<\/title>/)?.[1];

        const linkDocs = splittedText.map((text) => {
          return new Document({
            pageContent: text,
            metadata: {
              title: title || link,
              url: link,
            },
          });
        });

        docs.push(...linkDocs);
      } catch (err:any) {
        console.error(
          `Error at generating documents from links: ${err.message}`,
        );
        docs.push(
          new Document({
            pageContent: `Failed to retrieve content from the link: ${err.message}`,
            metadata: {
              title: 'Failed to retrieve content',
              url: link,
            },
          }),
        );
      }
    }),
  );

  return docs;
};

const Textarea = memo(() => {
	const { input, setInput, emptyInput } = useInput();
	const textareaRef = useRef<HTMLTextAreaElement | null>(null);
	const { isLoading, handleFormSubmit } = useChat();
	const { attachments, addAttachment } = useAttachments();
	const { searchMode } = useSearchMode();
	const {inputRef} = useAppResize();
	
	const handleKeyDown = async (e: React.KeyboardEvent) => {
		if (e.key === "Enter" && e.ctrlKey) {
			e.preventDefault();
			handleFormSubmit(input, attachments, searchMode, emptyInput);
		}
		if (e.ctrlKey && e.key === "v") {
			e.preventDefault();
			const clipboardItems = await navigator.clipboard.read();
			for (const item of clipboardItems) {
				if (item.types.some((type) => type.includes("image"))) {
					const type = item.types.find((type) => type.includes("image"));
					const blob = await item.getType(type);
					const file = new File(
						[blob],
						`clipboard-image.${type.split("/")[1]}`,
						{
							type: `image/${type.split("/")[1]}`,
						}
					);
					const base64 = await readFileAsBase64(file).then((base64) => base64);
					addAttachment({
						id: `clipboard-image-${Date.now()}`,
						metadata: {
							name: `clipboard-image.${type.split("/")[1]}`,
							type: `image/${type.split("/")[1]}`,
							size: blob.size,
							lastModified: Date.now(),
						},
						type: "image",
						base64: `data:${file.type};base64,${base64}`,
					});
					break;
				}
				if (item.types.some((type) => type.includes("text/plain"))) {
					const type = item.types.find((type) => type.includes("text/plain"));
					const text = await (await item.getType(type)).text();
					if(text.length > 1000){
					addAttachment({
						id: `${text}-${Date.now()}-${Math.random()
							.toString(36)
							.substring(7)}`,
						text,
						type: "text",
						base64: "",
					});
				}
				else{
				setInput(prev => prev + text);	
				}
					break;
				}
			}
		}
	};
	return (
		<AutosizeTextarea
			ref={(ref) => {
				if (ref) {
					(textareaRef as any).current = ref.textArea;
					(inputRef as any).current = ref.textArea;
				}
			}}
			disabled={isLoading.state}
			value={input}
			maxHeight={150}
			onChange={(e) => setInput(e.target.value)}
			placeholder="Message Chat Bot"
			className="border-none resize-none focus-visible:ring-0 focus-visible:ring-offset-0  min-h-[200px] max-h-[400px] focus:outline-none scrollbar-thin scrollbar-thumb-neutral-600 scrollbar-track-transparent hover:scrollbar-thumb-neutral-500"
			onKeyDown={handleKeyDown}
			rows={1}
		/>
	);
});

