const handleKeyDown = (event: KeyboardEvent) => {
      
      if (event.key === "Escape") {
        if (cropArea) {
          setCropArea(null);
        } else {
          getCurrentWindow().hide();
        }
        return;
      }

      // Tool shortcuts
      if (!showTextInput) {
        switch (event.key.toLowerCase()) {
          case "s":
            setCurrentTool("select");
            break;
          case "r":
            setCurrentTool("rectangle");
            break;
          case "t":
            setCurrentTool("text");
            break;
          case "p":
            setCurrentTool("pencil");
            break;
          case "a":
            setCurrentTool("arrow");
            break;
          case "z":
            if (event.ctrlKey || event.metaKey) {
              event.preventDefault();
              if (event.shiftKey) {
                handleRedo();
              } else {
                handleUndo();
              }
            }
            break;
          case "y":
            if (event.ctrlKey || event.metaKey) {
              event.preventDefault();
              handleRedo();
            }
            break;
          case "enter":
            if (cropArea) {
              applyCrop();
              return;
            }
            handleSave();
            break;
        }
      }
    };

