const VerticalMessageDisplay = memo(function MessageDisplay() {
  const { ActiveWindow } = useAppResize();
  const { vertical } = useConfig();
  const { messages, error, rewrite, lastMessage, pinnedMessage } = useChat();
  let displayMessage = null;
  if(vertical)
  displayMessage = vertical === "last" ? lastMessage : vertical == 'pinned' ? pinnedMessage:null;

  if (!displayMessage) return null;
  if (ActiveWindow !== "chat") return null;

  const displayMessageVisible =
    (!!displayMessage?.content ||
      !!displayMessage?.attachments ||
      !!displayMessage?.action) && !displayMessage.hidden

  if (!displayMessageVisible && !error) return null;

  return (
    <MessageDisplayWrapper LAYOUT_MODE={'vertical'}>
      <div
        className={cn(
          "w-full  overflow-hidden max-h-48",
        )}
