const formatKey = (key: string): string => {
  if (KEY_SYMBOLS[key]) {
    return KEY_SYMBOLS[key];
  }

  if (key.startsWith("Key")) {
    return key.replace("Key", "");
  }

  if (key.startsWith("Digit")) {
    return key.replace("Digit", "");
  }

  if (key.startsWith("Numpad")) {
    return key.replace("Numpad", "");
  }

  return key;
};

const sortKeys = (keys: string[]): string[] => {
  const modifierOrder = ["Control", "Alt", "Shift", "Meta", "Command"];

  return [...keys].sort((a, b) => {
    const aIndex = modifierOrder.indexOf(a);
    const bIndex = modifierOrder.indexOf(b);

    if (aIndex === -1 && bIndex === -1) return 0;
    if (aIndex === -1) return 1;
    if (bIndex === -1) return -1;
    return aIndex - bIndex;
  });
};

const readFileAsBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      if (typeof reader.result === "string") {
        resolve(reader.result.split(",")[1]);
      } else {
        reject(new Error("Failed to read file as base64"));
      }
    };
    reader.onerror = (error) => reject(error);
    reader.readAsDataURL(file);
  });
};

const parseTaskJson = (jsonString: string): LearningTask[] => {
	const data = JSON.parse(jsonString);

	if (!Array.isArray(data)) {
		throw new Error("Invalid Task JSON: The root of the JSON must be an array.");
	}

	for (const task of data) {
		// Validate base required fields
		if (!task.title || !task.task_type || !task.tree_id || !task.tree_name) {
			throw new Error(
				`Invalid Task JSON: A task is missing one of the required fields: title, task_type, tree_id, or tree_name.`
			);
		}
		// Validate node_ids
		if (
			!task.node_ids ||
			!Array.isArray(task.node_ids) ||
			task.node_ids.length === 0
		) {
			throw new Error(
				`Invalid Task JSON: Field 'node_ids' must be a non-empty array for task: "${task.title}".`
			);
		}
		// Validate node_paths
		if (
			!task.node_paths ||
			!Array.isArray(task.node_paths) ||
			task.node_paths.length === 0
		) {
			throw new Error(
				`Invalid Task JSON: Field 'node_paths' must be a non-empty array for task: "${task.title}".`
			);
		}
	}
	return data as LearningTask[];
};

const parseTaskFile = async (file: File): Promise<LearningTask[]> => {
	const text = await file.text();

	if (file.name.endsWith(".json")) {
		return parseTaskJson(text);
	}

	throw new Error("Unsupported file format. Please use .json");
};

